const SB_URL = $('Config').first().json.SUPABASE_URL;
const SB_KEY = $('Config').first().json.SUPABASE_SERVICE_KEY;
const _h = this.helpers;

async function sbGet(path) {
  try {
    const res = await _h.httpRequest({ method: 'GET', url: SB_URL + '/rest/v1/' + path, headers: { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY }, json: true });
    return Array.isArray(res) ? res : [];
  } catch(e) { return []; }
}

async function sbPost(path, body) {
  try {
    await _h.httpRequest({ method: 'POST', url: SB_URL + '/rest/v1/' + path, headers: { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY, 'Content-Type': 'application/json', Prefer: 'return=minimal' }, body: JSON.stringify(body) });
    return true;
  } catch(e) { return false; }
}

async function sbPostReturn(path, body) {
  try {
    const res = await _h.httpRequest({ method: 'POST', url: SB_URL + '/rest/v1/' + path, headers: { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY, 'Content-Type': 'application/json', Prefer: 'return=representation' }, body: JSON.stringify(body) });
    return Array.isArray(res) ? res[0] : res;
  } catch(e) { return null; }
}

async function sbPatch(path, body) {
  try {
    await _h.httpRequest({ method: 'PATCH', url: SB_URL + '/rest/v1/' + path, headers: { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY, 'Content-Type': 'application/json', Prefer: 'return=minimal' }, body: JSON.stringify(body) });
    return true;
  } catch(e) { return false; }
}

async function sbRpc(fn, params) {
  try {
    await _h.httpRequest({ method: 'POST', url: SB_URL + '/rest/v1/rpc/' + fn, headers: { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY, 'Content-Type': 'application/json' }, body: JSON.stringify(params) });
    return true;
  } catch(e) { return false; }
}

async function ensureConversation(orgId, contactId) {
  const existing = await sbGet('conversations?organization_id=eq.' + orgId + '&contact_id=eq.' + contactId + '&channel=eq.reactivation&select=id&limit=1');
  if (existing.length) return existing[0].id;
  const row = await sbPostReturn('conversations', { organization_id: orgId, contact_id: contactId, channel: 'reactivation', mode: 'ai', status: 'active', started_at: new Date().toISOString() });
  return row ? row.id : null;
}

async function logMessage(conversationId, orgId, content) {
  if (!conversationId) return;
  await sbPost('messages', { conversation_id: conversationId, organization_id: orgId, role: 'assistant', content, content_type: 'text', created_at: new Date().toISOString() });
}

async function waSend(phoneNumberId, accessToken, payload) {
  await _h.httpRequest({ method: 'POST', url: 'https://graph.facebook.com/v21.0/' + phoneNumberId + '/messages', headers: { Authorization: 'Bearer ' + accessToken, 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
}

function todayStr() { return new Date().toISOString().slice(0, 10); }
function daysAgo(n) { const d = new Date(); d.setDate(d.getDate() - n); return d.toISOString(); }
function billingPeriod() { const d = new Date(); return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0'); }
function getOrgHour(tz) { try { return parseInt(new Intl.DateTimeFormat('en-US', { hour: 'numeric', hour12: false, timeZone: tz }).format(new Date()), 10); } catch { return new Date().getUTCHours() + 3; } }
function parseHour(t) { return parseInt((t || '09:00').split(':')[0], 10); }

const workflows = await sbGet('org_workflows?template_id=eq.reactivation_chat&is_active=eq.true&select=id,organization_id,config');

if (!workflows.length) {
  return [{ json: { processed: 0, message: 'No active reactivation workflows' } }];
}

const results = [];

for (const wf of workflows) {
  const orgId = wf.organization_id;
  const cfg = wf.config || {};
  const inactiveDays   = Math.max(cfg.inactive_days || 30, 30);
  const cooldownDays   = cfg.cooldown_days || 30;
  const dailyLimit     = cfg.daily_limit || 50;
  const timezone       = cfg.timezone || 'Europe/Istanbul';
  const whStart        = parseHour(cfg.working_hours_start || '09:00');
  const whEnd          = parseHour(cfg.working_hours_end || '17:00');
  const targetStatuses = (cfg.target_statuses || 'lost,new,in_progress').split(',');

  const sequence = cfg.sequence || [];
  const step1Template   = sequence.length > 0 ? sequence[0].template : (cfg.message_template || '');
  const step1ParamCount = sequence.length > 0 ? (sequence[0].param_count || 0) : (Number(cfg.template_param_count) || 0);
  const maxStep = sequence.length > 0 ? sequence.length : 1;

  const orgHour = getOrgHour(timezone);
  if (orgHour < whStart || orgHour >= whEnd) {
    results.push({ org: orgId, status: 'skip', reason: 'outside_working_hours', orgHour, window: whStart + '-' + whEnd });
    continue;
  }

  if (!step1Template) { results.push({ org: orgId, status: 'skip', reason: 'no_template' }); continue; }

  const batchSize = Math.max(1, Math.ceil(dailyLimit / ((whEnd - whStart) * 2)));

  const period = billingPeriod();
  const usage = await sbGet('usage_counters?organization_id=eq.' + orgId + '&metric=eq.reactivation_lead_count&billing_period=eq.' + period + '&select=value&limit=1');
  const usedCount = (usage[0] && usage[0].value) || 0;

  const subRows = await sbGet('org_subscriptions?organization_id=eq.' + orgId + '&select=plan_id&limit=1');
  const planId = (subRows[0] && subRows[0].plan_id) || 'legacy';
  let effectiveLimit = 999999;
  if (planId !== 'legacy') {
    const entRows = await sbGet('plan_entitlements?plan_id=eq.' + planId + '&feature_key=eq.workflow_reactivation&select=limit_value&limit=1');
    const planLimit = (entRows[0] && entRows[0].limit_value) || 0;
    const ovr = await sbGet('org_entitlement_overrides?organization_id=eq.' + orgId + '&feature_key=eq.workflow_reactivation&select=limit_override&limit=1');
    effectiveLimit = (ovr[0] && ovr[0].limit_override) || planLimit;
  }
  if (usedCount >= effectiveLimit) { results.push({ org: orgId, status: 'skip', reason: 'quota_exceeded', used: usedCount, limit: effectiveLimit }); continue; }

  const todayRuns = await sbGet('workflow_runs?org_workflow_id=eq.' + wf.id + '&status=eq.success&created_at=gte.' + todayStr() + 'T00:00:00Z&select=id&limit=' + (dailyLimit + 1));
  if (todayRuns.length >= dailyLimit) { results.push({ org: orgId, status: 'skip', reason: 'daily_limit', sent_today: todayRuns.length }); continue; }

  let remaining = Math.min(batchSize, dailyLimit - todayRuns.length, effectiveLimit - usedCount);
  if (remaining <= 0) { results.push({ org: orgId, status: 'skip', reason: 'no_remaining' }); continue; }

  const orgRows = await sbGet('organizations?id=eq.' + orgId + '&select=channel_config,ai_persona&limit=1');
  const orgConfig = (orgRows[0] && orgRows[0].channel_config) || {};
  const waConfig = orgConfig.whatsapp || {};
  const creds = waConfig.credentials || {};
  const phoneNumberId = creds.phone_number_id || waConfig.phone_number_id;
  const accessToken = creds.access_token || waConfig.access_token;
  const orgLang = (orgRows[0] && orgRows[0].ai_persona && orgRows[0].ai_persona.language) || 'tr';
  const LANG_MAP = { en: 'en_US', de: 'de', tr: 'tr', ar: 'ar', fr: 'fr_FR' };
  const templateLangCode = LANG_MAP[orgLang] || orgLang;

  if (!phoneNumberId || !accessToken) { results.push({ org: orgId, status: 'skip', reason: 'no_wa_credentials' }); continue; }

  function buildTpl(phone, tplName, tplParamCount, contactName) {
    const p = { messaging_product: 'whatsapp', to: phone, type: 'template', template: { name: tplName, language: { code: templateLangCode } } };
    if (tplParamCount >= 1) { p.template.components = [{ type: 'body', parameters: [{ type: 'text', text: contactName || (orgLang === 'de' ? 'Geschätzter Kunde' : 'Değerli müşterimiz') }] }]; }
    return p;
  }

  let totalSent = 0, totalFailed = 0;
  const stepStats = {};

  // ═══ PHASE A — Step 1 ═══
  const cutoff = daysAgo(inactiveDays);
  const sf = targetStatuses.map(s => s.trim()).join(',');
  const inactiveLeads = await sbGet('leads?organization_id=eq.' + orgId + '&status=in.(' + sf + ')&updated_at=lte.' + cutoff + '&select=id,contact_id&order=updated_at.asc&limit=' + (remaining * 3));
  const coldCandidates = await sbGet('leads?organization_id=eq.' + orgId + '&status=in.(' + sf + ')&select=id,contact_id&order=created_at.asc&limit=' + (remaining * 3));

  let coldLeads = [];
  if (coldCandidates.length) {
    const cIds = [...new Set(coldCandidates.map(l => l.contact_id).filter(Boolean))];
    if (cIds.length) {
      const ec = await sbGet('conversations?organization_id=eq.' + orgId + '&contact_id=in.(' + cIds.join(',') + ')&select=contact_id');
      const hc = new Set(ec.map(c => c.contact_id));
      coldLeads = coldCandidates.filter(l => l.contact_id && !hc.has(l.contact_id));
    }
  }

  const seen = new Set();
  const allLeads = [];
  for (const l of [...inactiveLeads, ...coldLeads]) { if (l.contact_id && !seen.has(l.contact_id)) { seen.add(l.contact_id); allLeads.push(l); } }

  let s1Sent = 0, s1Fail = 0;
  if (allLeads.length > 0) {
    const aIds = allLeads.map(l => l.contact_id);
    const rr = await sbGet('workflow_runs?org_workflow_id=eq.' + wf.id + '&contact_id=in.(' + aIds.join(',') + ')&status=eq.success&created_at=gte.' + daysAgo(cooldownDays) + '&select=contact_id');
    const recentSet = new Set(rr.map(r => r.contact_id));

    let compSet = new Set();
    if (maxStep > 1) {
      const cr = await sbGet('workflow_runs?org_workflow_id=eq.' + wf.id + '&sequence_step=eq.' + maxStep + '&status=eq.success&contact_id=in.(' + aIds.join(',') + ')&select=contact_id');
      compSet = new Set(cr.map(r => r.contact_id));
    }

    const eligible = allLeads.filter(l => !recentSet.has(l.contact_id) && !compSet.has(l.contact_id)).slice(0, remaining);

    if (eligible.length > 0) {
      const bIds = eligible.map(l => l.contact_id);
      const contacts = await sbGet('contacts?id=in.(' + bIds.join(',') + ')&select=id,phone,full_name');
      const cm = {}; for (const c of contacts) cm[c.id] = c;

      for (const lead of eligible) {
        if (remaining <= 0) break;
        const ct = cm[lead.contact_id];
        if (!ct || !ct.phone) { s1Fail++; totalFailed++; continue; }
        const phone = ct.phone.replace(/^\+/, '');
        try {
          await waSend(phoneNumberId, accessToken, buildTpl(phone, step1Template, step1ParamCount, ct.full_name));
          await sbPost('workflow_runs', { org_workflow_id: wf.id, organization_id: orgId, contact_id: lead.contact_id, trigger_type: 'contact_inactive', status: 'success', sequence_step: 1, result: { template: step1Template, phone, lead_id: lead.id, step: 1 } });
          const convId = await ensureConversation(orgId, lead.contact_id);
          await logMessage(convId, orgId, '\ud83d\udce4 Step 1/' + maxStep + ' \u2014 ' + step1Template);
          s1Sent++; totalSent++; remaining--;
          await sbPatch('leads?contact_id=eq.' + lead.contact_id + '&organization_id=eq.' + orgId + '&status=in.(new,in_progress,lost)', { status: 'nurturing', updated_at: new Date().toISOString() });
          await sbRpc('increment_usage', { p_org_id: orgId, p_period: billingPeriod(), p_metric: 'reactivation_lead_count', p_amount: 1 });
        } catch (err) {
          s1Fail++; totalFailed++;
          await sbPost('workflow_runs', { org_workflow_id: wf.id, organization_id: orgId, contact_id: lead.contact_id, trigger_type: 'contact_inactive', status: 'failed', sequence_step: 1, result: { error: String(err), lead_id: lead.id, step: 1 } });
        }
      }
    }
  }
  stepStats.step1 = { sent: s1Sent, failed: s1Fail };

  // ═══ PHASE B — Steps 2..maxStep ═══
  if (maxStep > 1 && remaining > 0) {
    for (let sn = 2; sn <= maxStep; sn++) {
      if (remaining <= 0) break;
      const sc = sequence[sn - 1]; if (!sc) break;
      const st = sc.template || '', sp = sc.param_count || 0, dd = sc.delay_days || 0;
      if (!st || st.startsWith('TBD')) { stepStats['step' + sn] = { sent: 0, skipped: true, reason: 'tbd_template' }; continue; }

      const prev = await sbGet('workflow_runs?org_workflow_id=eq.' + wf.id + '&sequence_step=eq.' + (sn - 1) + '&status=eq.success&created_at=lte.' + daysAgo(dd) + '&select=contact_id');
      if (!prev.length) { stepStats['step' + sn] = { sent: 0, reason: 'no_prev_step_eligible' }; continue; }
      const pIds = [...new Set(prev.map(r => r.contact_id))];

      const already = await sbGet('workflow_runs?org_workflow_id=eq.' + wf.id + '&sequence_step=eq.' + sn + '&contact_id=in.(' + pIds.join(',') + ')&select=contact_id');
      const alreadySet = new Set(already.map(r => r.contact_id));
      const convos = await sbGet('conversations?organization_id=eq.' + orgId + '&contact_id=in.(' + pIds.join(',') + ')&select=contact_id');
      const replySet = new Set(convos.map(c => c.contact_id));
      const blocked = await sbGet('leads?organization_id=eq.' + orgId + '&contact_id=in.(' + pIds.join(',') + ')&status=in.(handed_off,converted)&select=contact_id');
      const blockSet = new Set(blocked.map(l => l.contact_id));

      const elig = pIds.filter(c => !alreadySet.has(c) && !replySet.has(c) && !blockSet.has(c)).slice(0, remaining);
      if (!elig.length) { stepStats['step' + sn] = { sent: 0, skipped_already: alreadySet.size, skipped_reply: replySet.size, skipped_blocked: blockSet.size }; continue; }

      const cts = await sbGet('contacts?id=in.(' + elig.join(',') + ')&select=id,phone,full_name');
      const cMap = {}; for (const c of cts) cMap[c.id] = c;
      let sSent = 0, sFail = 0;
      for (const cid of elig) {
        if (remaining <= 0) break;
        const ct = cMap[cid]; if (!ct || !ct.phone) { sFail++; totalFailed++; continue; }
        const phone = ct.phone.replace(/^\+/, '');
        try {
          await waSend(phoneNumberId, accessToken, buildTpl(phone, st, sp, ct.full_name));
          await sbPost('workflow_runs', { org_workflow_id: wf.id, organization_id: orgId, contact_id: cid, trigger_type: 'contact_inactive', status: 'success', sequence_step: sn, result: { template: st, phone, step: sn } });
          const convId = await ensureConversation(orgId, cid);
          await logMessage(convId, orgId, '\ud83d\udce4 Step ' + sn + '/' + maxStep + ' \u2014 ' + st);
          sSent++; totalSent++; remaining--;
          await sbRpc('increment_usage', { p_org_id: orgId, p_period: billingPeriod(), p_metric: 'reactivation_lead_count', p_amount: 1 });
        } catch (err) {
          sFail++; totalFailed++;
          await sbPost('workflow_runs', { org_workflow_id: wf.id, organization_id: orgId, contact_id: cid, trigger_type: 'contact_inactive', status: 'failed', sequence_step: sn, result: { error: String(err), step: sn } });
        }
      }
      stepStats['step' + sn] = { sent: sSent, failed: sFail, skipped_reply: replySet.size, skipped_complete: alreadySet.size, skipped_blocked: blockSet.size };
    }
  }

  results.push({ org: orgId, status: 'done', sent: totalSent, failed: totalFailed, steps: stepStats, maxStep, batch: batchSize });
}

return [{ json: { total_orgs: workflows.length, results } }];
